INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-02671', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關女性主義社會工作的敘述，下列何者錯誤？', '["同樣身為女性，社會工作者要扮演「社會女工匠」的角色，致力於改造個案，脫離被父權壓迫的命運", "社會工作者應與個案秉持一種平等的關係，讓個案可以釋放自己、自我肯定與學習新的知識與能力", "拒絕性別盲目的知識和技術，改採取承認女性經驗的方法，來修正實務工作模式", "尋求集體主義式的解決方案，但尊重每一位女性的個體性和獨特性，例如原住民婦女、身心障礙婦女、 新移民等"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02672', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列那一個社會工作實務原則不屬於社會心理學派的創見？', '["個別化原則", "人在情境中", "重視專業關係", "案主自我揭露"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02673', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在開個案研討會中，社會工作者稍微隱匿修改一下，然後將案主的資訊和與會者分享，事後也回收相關 資料；如此做法符合那一項專業倫理原則？', '["案主自決", "絕對保密", "相對保密", "最小傷害"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02674', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會福利組織受到購買式服務契約與私有化的影響，在組織倫理方面比較著重於那一方面？', '["社會工作者的個人成長", "組織績效", "志工福利", "社會工作者的專業成長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02675', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關社會工作不當執業與倫理原則的敘述，何者錯誤？', '["當社會工作者發現自己沒有能力處理個案的問題時，應立即向更有經驗的同事或督導尋求諮詢或轉介 個案進行其他服務", "提供督導的社會工作者應以公平的態度來評估受督導者的表現，而非考量人際關係與情分深淺", "為了幫助個案取得較好的福利資源，社會工作者在報告上故意誇大一下個案的可憐處境，是維護案主 利益優先的倫理", "發現主管在下班後與個案發生性關係，基於維護機構利益、對組織表示忠誠，應該想辦法揭露、告發 其行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02676', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有人主張臺灣的公民沒有義務提供非法移工任何服務與協助，且機構的工作人員應該舉發逃逸外勞使其 被遣返回國是合乎倫理的；這樣的主張是屬於何種倫理觀點？', '["利他主義", "行為的效用主義", "馬克斯主義", "相對論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02677', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「在我15歲到18歲時，一直有位社會工作者在幫助我，當我離開機構後，開始思考上大學這件事，他 就帶我到每一所我想去的大學參訪，指導我如何租屋、申請學校、填寫經濟補助申請、給我很多做人做 事的建議，也協助我順利找到打工工作，賺取生活費」，請問這位社會工作者在做的是什麼方案？', '["獨立生活服務", "青年住宅輔導員", "學生助學貸款審核", "收養前的中途之家"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02678', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '近年來校園的暴力、霸凌事件頻傳，學校社會工作在臺灣，似乎可以有更積極的介入角色。下列何者不 屬於學校社會工作的範圍？', '["協助處理校園性侵害與性騷擾事件", "預防並輔導青少年未婚懷孕個案", "協助新移民家庭子女生活適應", "催化學校女性教職員爭取性別平等工作運動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02679', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '精神病理社會工作的介入理論包括心理學、器質性理論、社會文化理論等觀點。請問下列敘述何者正確？', '["重視器質性因素的學派主要關注的是荷爾蒙、生化平衡、神經傳導素、基因等，介入上是以抗精神疾 病藥物為主的醫療處遇", "心理學觀點認為心理疾病本身並不存在，主要是社會文化對人產生壓迫與迷思，造成個體的潛意識衝突", "行為主義、認知學派關注於檢視人的訊息處理過程對行為的影響，建議改變社會歧視，屬於社會文化 觀點", "人文主義觀點強調以人為中心，發展個人能力與潛力，干預重點是降低幻想與妄想，使獲致動機與優勢"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02680', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關社會救助與社會保險的比較，下列那一項錯誤？', '["社會救助的對象主要是低收入者，社會保險主要的對象是有工作的人", "通常社會救助是以需求為基礎來進行資格認定，社會保險則是以有無繳納保費來認定受益資格", "雙軌式福利論認為社會救助帶有標籤與歧視，且受助者通常是女性，因為女人比較容易落入貧窮", "工作福利（workfare）是社會保險的主流概念，目的是為了鼓勵、支持就業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
